import{_ as e,o as d,c as o,ak as r}from"./chunks/framework.Dx0ZwfXr.js";const h=JSON.parse('{"title":"Support Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"articles/support-matrix.md","filePath":"articles/support-matrix.md"}'),a={name:"articles/support-matrix.md"};function i(s,t,n,c,l,p){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="support-matrix" tabindex="-1">Support Matrix <a class="header-anchor" href="#support-matrix" aria-label="Permalink to “Support Matrix”">​</a></h1><p><code>RoyalApps.Community.Rdp.WinForms</code> uses one shared <code>RdpClientConfiguration</code> model, but not every option is supported by both hosting modes.</p><p>Use this page as the contract for which features are valid in <code>Embedded</code> and <code>External</code> mode.</p><h2 id="feature-matrix" tabindex="-1">Feature Matrix <a class="header-anchor" href="#feature-matrix" aria-label="Permalink to “Feature Matrix”">​</a></h2><table tabindex="0"><thead><tr><th>Feature / setting</th><th>Embedded</th><th>External</th><th>Notes</th></tr></thead><tbody><tr><td>Full desktop session</td><td>Yes</td><td>Yes</td><td>The baseline session model in both modes.</td></tr><tr><td><code>Program</code> alternate shell</td><td>Yes</td><td>Yes</td><td>Desktop-session only. Cannot be combined with <code>RemoteApp</code>.</td></tr><tr><td><code>RemoteApp</code></td><td>No</td><td>Yes</td><td>Embedded mode rejects it during validation.</td></tr><tr><td><code>Display.UseMultimon</code></td><td>Yes</td><td>Yes</td><td>Embedded uses the ActiveX client property; external writes <code>use multimon</code>.</td></tr><tr><td><code>External.SelectedMonitors</code></td><td>No</td><td>Yes</td><td>External-only monitor targeting via <code>selectedmonitors</code>.</td></tr><tr><td><code>Connection.EnableRdsAadAuth</code></td><td>Yes</td><td>Yes</td><td>External writes <code>enablerdsaadauth</code>.</td></tr><tr><td><code>Security.AuthenticationServiceClass</code></td><td>Yes</td><td>No</td><td>Embedded-only ActiveX setting. It is not written to generated external <code>.rdp</code> files.</td></tr><tr><td><code>Security.DisableCredentialsDelegation</code></td><td>Yes</td><td>Limited</td><td>External support requires <code>External.UseMsRdpExHooks</code>.</td></tr><tr><td><code>Security.RedirectedAuthentication</code></td><td>Yes</td><td>Limited</td><td>External support requires <code>External.UseMsRdpExHooks</code>.</td></tr><tr><td><code>Security.RestrictedLogon</code></td><td>Yes</td><td>Limited</td><td>External support requires <code>External.UseMsRdpExHooks</code>.</td></tr><tr><td><code>Security.RemoteCredentialGuard</code></td><td>Yes</td><td>Limited</td><td>External support is only effective when the low-level flags are written through MsRdpEx hooks.</td></tr><tr><td><code>Security.RestrictedAdminMode</code></td><td>Yes</td><td>Limited</td><td>External support is only effective when the low-level flags are written through MsRdpEx hooks.</td></tr><tr><td>Zoom / smart sizing / direct <code>IRdpClient</code> access</td><td>Yes</td><td>No</td><td>External mode treats these as no-ops because the session runs in another process.</td></tr><tr><td>Temp <code>.rdp</code> file, launcher path, credential staging, process lifetime</td><td>No</td><td>Yes</td><td>These live under <code>RdpConfiguration.External</code>.</td></tr></tbody></table><h2 id="validation-rules" tabindex="-1">Validation Rules <a class="header-anchor" href="#validation-rules" aria-label="Permalink to “Validation Rules”">​</a></h2><p>The library validates unsupported combinations before connect instead of silently ignoring them.</p><ul><li><code>RemoteApp</code> is external-only.</li><li><code>Program</code> and <code>RemoteApp</code> cannot be combined in one connection.</li><li><code>External.SelectedMonitors</code> is external-only.</li></ul>',8)])])}const m=e(a,[["render",i]]);export{h as __pageData,m as default};
